if (params.column.colDef.field == "Duty Rate %") {
  multiOptionDuty = {
    name: 'Duty With $ and %',
    action: () => {
      const colField = getMasterFiledName('duty_rate');
      // Prefer the chosen vendor's quote FOB country; fall back to any vendor row
      // that has one set. The dialog uses this to auto-look-up Trump 2025.
      const vendors: any[] = params.node.data.Vendors ?? [];
      const chosen = params.node.data[getMasterFiledName('chosen_vendor')]?.title;
      const matchVendor = chosen ? vendors.find(v => v?.Vendor?.factory_nickname === chosen) : null;
      const fobCountry = matchVendor?.['FOB Country']
                      ?? vendors.find(v => !!v?.['FOB Country'])?.['FOB Country']
                      ?? null;

      const dialogRef = window['dialog'].open(DutyRateDialogomponent, {
        disableClose: true,
        data: {
          fob_cost:      params.node.data[getMasterFiledName('fob_cost')],
          dollarAmount:  params.node.data['duty_rate_dollar_amount'],
          // Pass both the evaluated total (legacy fallback) and the stored
          // equation so the dialog can show the breakdown when re-opened.
          percentAmount: params.node.data[colField]?.title,
          equation:      params.node.data['rfqItem_duty_rate_equation']
                      ?? params.node.data[colField + '_equation']
                      ?? null,
          fobCountry,
          // Provide description and license list so the AI panel can classify
          desc:     params.node.data[getMasterFiledName('desc')] ?? '',
          licenses: Object.keys(this.licenseRateMap),
        }
      });

      dialogRef.afterClosed().subscribe(async (result) => {
        if (!result) return;
        const { duty_rate, duty_rate_equation, duty_rate_dollar_amount } = result;

        // duty_rate from the dialog is the evaluated total as a string;
        // keep storing it in `title` (downstream math uses parseFloat).
        // The raw equation goes into rfqItem_duty_rate_equation (persisted
        // to DB) AND into <colField>_equation (consumed by MathExprCellEditor
        // to restore the breakdown when the cell is re-opened).
        params.node.setData({
          ...params.node.data,
          duty_rate_dialog:                true,
          duty_rate_dollar_amount,
          rfqItem_duty_rate_equation:      duty_rate_equation ?? null,
          [colField + '_equation']:        duty_rate_equation ?? null,
          [colField]: { title: duty_rate, duty_rate_dollar_amount },
        });
      });

    }
  };

}

if (window['role'] == 'admin') {
  containerDialog = {
    name: 'use alt ctr px',
    action: () => {
      const dialogRef = window['dialog'].open(ContainerCostDialogomponent, {
        disableClose: true,
        data: {
          containercost: params.node.data.containercost
        }
      });

      dialogRef.afterClosed().subscribe(async (result) => {
        if (result) {
          if (params.node) {
            let selectedRowData = params.api.getSelectedNodes()
            if (selectedRowData.length) {

              new Promise(async (resolve, reject) => {
                try {
                  const data: any = await firstValueFrom(itemService.getWhse());
                  let effectedItems = []
                  for (let i = 0; selectedRowData.length > i; i++) {
                    if (selectedRowData[i].data[getMasterFiledName('fob_cost')]) {
                      selectedRowData[i].data.whsecost = data[0].RFQWhse_price
                      selectedRowData[i].data = selectedRowData[i].data
                      if (selectedRowData[i].data[getMasterFiledName('case_pack')] && selectedRowData[i].data['CBM/pc'] && selectedRowData[i].data['containercost']) {
                        let frtCostPerCBM = parseFloat(result.title) / 60;
                        let freight = parseFloat(selectedRowData[i].data['CBM/pc']) * frtCostPerCBM
                        selectedRowData[i].data[getMasterFiledName('freight')] = freight.toFixed(7);
                        selectedRowData[i].column = null
                        await window['equation'].recalculate_Lic_Gen(selectedRowData[i], window['colHeaders']);
                        selectedRowData[i].data.rfq_container_id_fk = result.id;
                        effectedItems.push(selectedRowData[i])
                      } else {
                        window['_snackBar'].open(`Case pack cbm/pc and container cost is requierd for the item ${selectedRowData[i].data['Price Code']}.`, 'close')
                        reject({ res: false })
                        break;
                      }
                    } else {
                      window['_snackBar'].open(`Case pack cbm/pc and container cost is requierd  for the item ${selectedRowData[i].data['Price Code']}.`, 'close')
                      reject({ res: false });
                      break;
                    }
                  }
                  resolve({ res: true, effectedItems: effectedItems })
                } catch (err) {
                  console.error('[Rfq] getWhse failed:', err);
                }
              }).then(async (value: any) => {
                if (value.res) {
                  for (let i = 0; value.effectedItems.length > i; i++) {
                    try {
                      const res: any = await firstValueFrom(itemService.updateRfqItem(value.effectedItems[i].data));
                      params.api.applyTransaction({ update: [selectedRowData[i].data] });
                    } catch (err) {
                      console.error('[Rfq] data) failed:', err);
                    }

