160	   *   canRunAi    = sales, sales_manager, production, sourcing_manager, admin.
161	   *
162	   * Sales users see the full duty rate flow including AI classification, but
163	   * cannot edit any field or apply AI results to the breakdown.
164	   */
165	  readonly canEditDuty: boolean;
166	  readonly canRunAi: boolean;
167	
168	  constructor(
169	    private itemService: itemService,
170	    public dialogRef: MatDialogRef<DutyRateDialogomponent>,
171	    @Inject(MAT_DIALOG_DATA) public data: DialogData,
172	    public dialog: MatDialog,
173	    private _snakcbar: MatSnackBar,
174	    private fb: UntypedFormBuilder,
175	    private crossService: CrossService,
176	    private htsClassifier: HtsClassifierService,
177	    private aiSettings: AiSettingsService,
178	    private roleGuard: RoleGuardService,
179	  ) {
180	    this.userRole = String(this.roleGuard.getRole() ?? '').trim().toLowerCase();
181	    const isSales = this.userRole === 'sales' || this.userRole === 'sales_manager';
182	    this.canEditDuty = !isSales;
183	    this.canRunAi = ['admin', 'sales', 'sales_manager', 'production', 'sourcing_manager']
184	      .includes(this.userRole);
185	  }
186	
187	  ngOnInit() {
188	    this.fobCountry = this.data.fobCountry?.trim() || null;
189	
190	    // Prefer the stored equation (preserves user-entered breakdown) over the
191	    // evaluated total, falling back to the total when the equation is absent.
192	    const source = this.data.equation ?? this.data.percentAmount;
193	    const parts  = splitDutyRateEquation(source);
194	
195	    this.form = this.fb.group({
196	      dollarAmount:    [this.data.dollarAmount],
197	      mfnRate:         [parts.mfn,   Validators.required],
198	      section301Rate:  [parts.s301],
199	      trump2025Rate:   [parts.trump],
200	    });
201	
202	    // View-only roles get a disabled form. They can still see values, open
203	    // CROSS, and run AI classification — but cannot mutate the breakdown.
204	    if (!this.canEditDuty) {
205	      this.form.disable();
206	    }
207	
208	    // Auto-fill Trump 2025 from the admin list if this row has an FOB country
209	    // and the breakdown's Trump field is empty (don't clobber user edits).
210	    if (this.fobCountry && !parts.trump) {
211	      this.aiSettings.lookupTrump2025(this.fobCountry).subscribe({
212	        next: r => {
213	          this.trump2025Result = r;
214	          if (r.found && r.rate != null) {
215	            this.form.patchValue({ trump2025Rate: String(r.rate) });
216	          }
217	        },
218	        error: () => {
219	          this.trump2025Result = { found: false, country: null, rate: null, matchedAs: null };
220	        },
221	      });
222	    }
223	  }
224	
225	  /**
226	   * The most recent classification code returned by the AI, used to deep-link
227	   * the "Open on USITC ↗" hint. Looking at the latest turn instead of caching
228	   * a separate field keeps state in one place.
229	   */
230	  get latestClassificationCode(): string | null {
231	    for (let i = this.chatTurns.length - 1; i >= 0; i--) {
232	      const code = this.chatTurns[i].classification?.hts_code;
233	      if (code) return code;
234	    }
235	    return null;
236	  }
237	
238	  /**
239	   * Format a turn's usage telemetry as a compact one-liner.
240	   * Example: "3,420 cached + 412 new · 215 completion · cache hit 89% · $0.0042"
241	   * Returns null when there's no usage data (non-DeepSeek provider with no usage).
242	   */
243	  formatUsage(usage: ChatUsage | null | undefined, cost?: number | null): string | null {
244	    if (!usage) return null;
245	    const hit  = usage.prompt_cache_hit_tokens  || 0;
246	    const miss = usage.prompt_cache_miss_tokens || 0;
247	    const comp = usage.completion_tokens || 0;
248	    const prompt = usage.prompt_tokens || (hit + miss);
249	    const parts: string[] = [];
250	    if (hit || miss) {
251	      parts.push(`${hit.toLocaleString()} cached + ${miss.toLocaleString()} new`);
252	      const total = hit + miss;
253	      if (total > 0) parts.push(`cache hit ${Math.round((hit / total) * 100)}%`);
254	    } else {
255	      parts.push(`${prompt.toLocaleString()} prompt`);
256	    }
257	    if (comp) parts.push(`${comp.toLocaleString()} completion`);
258	    if (usage.reasoning_tokens) parts.push(`${usage.reasoning_tokens.toLocaleString()} reasoning`);
259	    if (cost != null && cost > 0) parts.push(`$${cost.toFixed(4)}`);
260	    return parts.join(' · ');
261	  }
262	
263	  /** Sum of the three breakdown fields, parsed leniently. Returns 0 on parse failure. */
264	  get computedPercentTotal(): number {
265	    const safe = (v: any): number => {
266	      const s = (v ?? '').toString().trim();
267	      if (!s) return 0;
268	      try { return evaluateInput(s); } catch { return 0; }
269	    };
270	    return safe(this.form?.value?.mfnRate)
271	         + safe(this.form?.value?.section301Rate)
272	         + safe(this.form?.value?.trump2025Rate);
273	  }
274	
275	  // ── Form actions ────────────────────────────────────────────────────────────
276	
277	  onSave() {
278	    // MFN is the only required rate. Section 301 and Trump 2025 default to 0
279	    // when blank (a missing reciprocal tariff means 0%, not "invalid").
280	    if (!this.form.value.mfnRate?.toString().trim()) {
281	      this._snakcbar.open('Enter the MFN base rate', 'close');
282	      return;
283	    }
284	    try {
285	      const mfn   = evaluateInput(this.form.value.mfnRate.toString());
286	      const s301  = this.form.value.section301Rate?.toString().trim()
287	                    ? evaluateInput(this.form.value.section301Rate.toString()) : 0;
288	      const trump = this.form.value.trump2025Rate?.toString().trim()
289	                    ? evaluateInput(this.form.value.trump2025Rate.toString()) : 0;
290	
291	      const equation = buildDutyRateEquation(mfn, s301, trump);
292	      const total    = mfn + s301 + trump;
293	
294	      const dollarRaw = this.form.value.dollarAmount;
295	      const dollarVal = dollarRaw?.toString().trim() ? evaluateInput(dollarRaw.toString()) : 0;
296	
297	      this.dialogRef.close({
298	        // The grid evaluates `duty_rate` for math and uses `equation` only to
299	        // restore the user-facing breakdown when the cell is re-opened.
300	        duty_rate:                 total.toString(),
301	        duty_rate_equation:        equation,
302	        duty_rate_dollar_amount:   dollarVal.toString(),
303	        // Per-component breakdown — exposed so future consumers (e.g. cost
304	        // reports) can show the split without re-parsing the equation.
305	        breakdown: { mfn, section301: s301, trump2025: trump, total },
306	      });
307	    } catch {
308	      this._snakcbar.open('Invalid expression — use numbers and + - * / ( ) only.', 'close');
309	    }
310	  }
311	
312	  onCancel() {
313	    this.dialogRef.close();
314	  }
315	
316	  // ── CROSS lookup ────────────────────────────────────────────────────────────
317	
318	  toggleCross() {
319	    this.showCross = !this.showCross;

