 *   canRunAi    = sales, sales_manager, production, sourcing_manager, admin.
 *
 * Sales users see the full duty rate flow including AI classification, but
 * cannot edit any field or apply AI results to the breakdown.
 */
readonly canEditDuty: boolean;
readonly canRunAi: boolean;

constructor(
  private itemService: itemService,
  public dialogRef: MatDialogRef<DutyRateDialogomponent>,
  @Inject(MAT_DIALOG_DATA) public data: DialogData,
  public dialog: MatDialog,
  private _snakcbar: MatSnackBar,
  private fb: UntypedFormBuilder,
  private crossService: CrossService,
  private htsClassifier: HtsClassifierService,
  private aiSettings: AiSettingsService,
  private roleGuard: RoleGuardService,
) {
  this.userRole = String(this.roleGuard.getRole() ?? '').trim().toLowerCase();
  const isSales = this.userRole === 'sales' || this.userRole === 'sales_manager';
  this.canEditDuty = !isSales;
  this.canRunAi = ['admin', 'sales', 'sales_manager', 'production', 'sourcing_manager']
    .includes(this.userRole);
}

ngOnInit() {
  this.fobCountry = this.data.fobCountry?.trim() || null;

  // Prefer the stored equation (preserves user-entered breakdown) over the
  // evaluated total, falling back to the total when the equation is absent.
  const source = this.data.equation ?? this.data.percentAmount;
  const parts  = splitDutyRateEquation(source);

  this.form = this.fb.group({
    dollarAmount:    [this.data.dollarAmount],
    mfnRate:         [parts.mfn,   Validators.required],
    section301Rate:  [parts.s301],
    trump2025Rate:   [parts.trump],
  });

  // View-only roles get a disabled form. They can still see values, open
  // CROSS, and run AI classification — but cannot mutate the breakdown.
  if (!this.canEditDuty) {
    this.form.disable();
  }

  // Auto-fill Trump 2025 from the admin list if this row has an FOB country
  // and the breakdown's Trump field is empty (don't clobber user edits).
  if (this.fobCountry && !parts.trump) {
    this.aiSettings.lookupTrump2025(this.fobCountry).subscribe({
      next: r => {
        this.trump2025Result = r;
        if (r.found && r.rate != null) {
          this.form.patchValue({ trump2025Rate: String(r.rate) });
        }
      },
      error: () => {
        this.trump2025Result = { found: false, country: null, rate: null, matchedAs: null };
      },
    });
  }
}

/**
 * The most recent classification code returned by the AI, used to deep-link
 * the "Open on USITC ↗" hint. Looking at the latest turn instead of caching
 * a separate field keeps state in one place.
 */
get latestClassificationCode(): string | null {
  for (let i = this.chatTurns.length - 1; i >= 0; i--) {
    const code = this.chatTurns[i].classification?.hts_code;
    if (code) return code;
  }
  return null;
}

/**
 * Format a turn's usage telemetry as a compact one-liner.
 * Example: "3,420 cached + 412 new · 215 completion · cache hit 89% · $0.0042"
 * Returns null when there's no usage data (non-DeepSeek provider with no usage).
 */
formatUsage(usage: ChatUsage | null | undefined, cost?: number | null): string | null {
  if (!usage) return null;
  const hit  = usage.prompt_cache_hit_tokens  || 0;
  const miss = usage.prompt_cache_miss_tokens || 0;
  const comp = usage.completion_tokens || 0;
  const prompt = usage.prompt_tokens || (hit + miss);
  const parts: string[] = [];
  if (hit || miss) {
    parts.push(`${hit.toLocaleString()} cached + ${miss.toLocaleString()} new`);
    const total = hit + miss;
    if (total > 0) parts.push(`cache hit ${Math.round((hit / total) * 100)}%`);
  } else {
    parts.push(`${prompt.toLocaleString()} prompt`);
  }
  if (comp) parts.push(`${comp.toLocaleString()} completion`);
  if (usage.reasoning_tokens) parts.push(`${usage.reasoning_tokens.toLocaleString()} reasoning`);
  if (cost != null && cost > 0) parts.push(`$${cost.toFixed(4)}`);
  return parts.join(' · ');
}

/** Sum of the three breakdown fields, parsed leniently. Returns 0 on parse failure. */
get computedPercentTotal(): number {
  const safe = (v: any): number => {
    const s = (v ?? '').toString().trim();
    if (!s) return 0;
    try { return evaluateInput(s); } catch { return 0; }
  };
  return safe(this.form?.value?.mfnRate)
       + safe(this.form?.value?.section301Rate)
       + safe(this.form?.value?.trump2025Rate);
}

// ── Form actions ────────────────────────────────────────────────────────────

onSave() {
  // MFN is the only required rate. Section 301 and Trump 2025 default to 0
  // when blank (a missing reciprocal tariff means 0%, not "invalid").
  if (!this.form.value.mfnRate?.toString().trim()) {
    this._snakcbar.open('Enter the MFN base rate', 'close');
    return;
  }
  try {
    const mfn   = evaluateInput(this.form.value.mfnRate.toString());
    const s301  = this.form.value.section301Rate?.toString().trim()
                  ? evaluateInput(this.form.value.section301Rate.toString()) : 0;
    const trump = this.form.value.trump2025Rate?.toString().trim()
                  ? evaluateInput(this.form.value.trump2025Rate.toString()) : 0;

    const equation = buildDutyRateEquation(mfn, s301, trump);
    const total    = mfn + s301 + trump;

    const dollarRaw = this.form.value.dollarAmount;
    const dollarVal = dollarRaw?.toString().trim() ? evaluateInput(dollarRaw.toString()) : 0;

    this.dialogRef.close({
      // The grid evaluates `duty_rate` for math and uses `equation` only to
      // restore the user-facing breakdown when the cell is re-opened.
      duty_rate:                 total.toString(),
      duty_rate_equation:        equation,
      duty_rate_dollar_amount:   dollarVal.toString(),
      // Per-component breakdown — exposed so future consumers (e.g. cost
      // reports) can show the split without re-parsing the equation.
      breakdown: { mfn, section301: s301, trump2025: trump, total },
    });
  } catch {
    this._snakcbar.open('Invalid expression — use numbers and + - * / ( ) only.', 'close');
  }
}

onCancel() {
  this.dialogRef.close();
}

// ── CROSS lookup ────────────────────────────────────────────────────────────

toggleCross() {
  this.showCross = !this.showCross;

