import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, of } from 'rxjs';
import { catchError, map } from 'rxjs/operators';
import { environment } from 'src/environments/environment';

export interface OpenRouterModel {
  id: string;
  name: string;
  description?: string;
  context_length?: number;
  pricing?: { prompt: string; completion: string; prompt_cache?: string };
}

@Injectable({ providedIn: 'root' })
export class AiSettingsService {
  private base = environment.url;
  constructor(private http: HttpClient) {}

  /**
   * Get the model list for a specific API backend.
   *   'openrouter'      → full OpenRouter catalog (default)
   *   'deepseek-direct' → hardcoded list of DeepSeek-native models (v4-pro, v4-flash)
   */
  getAvailableModels(api: 'openrouter' | 'deepseek-direct' = 'openrouter'): Observable<{ data: OpenRouterModel[] }> {
    return this.http.get<{ data: OpenRouterModel[] }>(`${this.base}/api/openrouter/models`, { params: { api } });
  }

  /** Fetch metadata for a single model by ID. Returns null on error or not found. */
  getModelInfo(modelId: string, api: 'openrouter' | 'deepseek-direct' = 'openrouter'): Observable<OpenRouterModel | null> {
    return this.getAvailableModels(api).pipe(
      map(res => res.data.find(m => m.id === modelId) ?? null),
      catchError(() => of(null)),
    );
  }

  getCurrentModel(): Observable<{ key: string; value: string | null }> {
    return this.http.get<{ key: string; value: string | null }>(`${this.base}/api/admin/app-settings/ai-model`);
  }

  saveModel(modelId: string): Observable<{ key: string; value: string }> {
    return this.http.put<{ key: string; value: string }>(`${this.base}/api/admin/app-settings/ai-model`, { value: modelId });
  }

  /** API backend setting: 'openrouter' or 'deepseek-direct'. Forces routing in the backend. */
  getCurrentApi(): Observable<{ key: string; value: string | null }> {
    return this.http.get<{ key: string; value: string | null }>(`${this.base}/api/admin/app-settings/ai-api`);
  }

  saveApi(api: 'openrouter' | 'deepseek-direct'): Observable<{ key: string; value: string }> {
    return this.http.put<{ key: string; value: string }>(`${this.base}/api/admin/app-settings/ai-api`, { value: api });
  }

  getReasoningEffort(): Observable<{ key: string; value: string | null }> {
    return this.http.get<{ key: string; value: string | null }>(`${this.base}/api/admin/app-settings/ai-reasoning-effort`);
  }

  saveReasoningEffort(effort: string): Observable<{ key: string; value: string }> {
    return this.http.put<{ key: string; value: string }>(`${this.base}/api/admin/app-settings/ai-reasoning-effort`, { value: effort });
  }

  /**
   * Get a summary of the currently stored Section 301 data.
   * Returns { loaded: false } if no data has been uploaded yet.
   */
  getSection301Status(): Observable<{ loaded: boolean; codesFound?: number; lists?: string[] }> {
    return this.http.get<{ loaded: boolean; codesFound?: number; lists?: string[] }>(
      `${this.base}/api/admin/section301/status`,
    );
  }

  /**
   * Upload a Section 301 PDF to the backend for parsing.
   * Returns { codesFound: number, lists: string[] }.
   */
  uploadSection301Pdf(file: File): Observable<{ codesFound: number; lists: string[] }> {
    const form = new FormData();
    form.append('pdf', file, file.name);
    return this.http.post<{ codesFound: number; lists: string[] }>(
      `${this.base}/api/admin/section301/upload`,
      form,
    );
  }

  /**
   * Upload a Section 301 CSV. Preferred over the PDF uploader because the
   * column-addressed parser doesn't suffer from pdf-parse text-extraction
   * misordering. The backend returns a richer summary (skipped/conflicts/
   * lineErrors) so the admin can verify the import.
   */
  uploadSection301Csv(file: File): Observable<Section301CsvSummary> {
    const form = new FormData();
    form.append('csv', file, file.name);
    return this.http.post<Section301CsvSummary>(
      `${this.base}/api/admin/section301/upload-csv`,
      form,
    );
  }

  /**
   * Look up a single HTS code in the stored Section 301 tariff data.
   * Returns the list, rate, and description if found.
   */
  lookupSection301(htsCode: string): Observable<Section301Result> {
    return this.http.get<Section301Result>(
      `${this.base}/api/admin/section301/lookup`,
      { params: { hts: htsCode } },
    );
  }

  /**
   * Admin: read / write the per-HTS-code Section 301 overrides. Stored in
   * app_settings.section301_overrides as a JSON object keyed by HTS code:
   *   { "4414.10.00": { list: "List 4A", rate: 7.5, description: "..." } }
   * Backed by the generic /api/admin/app-settings endpoint.
   */
  getSection301Overrides(): Observable<{ key: string; value: string | null }> {
    return this.http.get<{ key: string; value: string | null }>(
      `${this.base}/api/admin/app-settings/section301_overrides`,
    );
  }
  saveSection301Overrides(overrides: Section301OverrideMap): Observable<{ key: string; value: string }> {
    return this.http.put<{ key: string; value: string }>(
      `${this.base}/api/admin/app-settings/section301_overrides`,
      { value: JSON.stringify(overrides) },
    );
  }

  /**
   * Look up the MFN base tariff rate for an HTS code against the bundled
   * USITC HTS revision. Backend falls back 10→8→6-digit prefix automatically.
   * On 404 the call still returns a HtsRateResult with found=false (mapped
   * client-side via catchError).
   */
  lookupHtsRate(htsCode: string): Observable<HtsRateResult> {
    return this.http.get<HtsRateResult>(
      `${this.base}/api/admin/hts-rates/lookup`,
      { params: { hts: htsCode } },
    );
  }

  // ── Trump 2025 reciprocal tariffs ───────────────────────────────────────────

  /** Read the full country → rate list. Empty when admin hasn't configured one yet. */
  getTrump2025List(): Observable<{ list: Trump2025Entry[] }> {
    return this.http.get<{ list: Trump2025Entry[] }>(
      `${this.base}/api/admin/trump2025/list`,
    );
  }

  /** Replace the full country → rate list (admin only). */
  saveTrump2025List(list: Trump2025Entry[]): Observable<{ list: Trump2025Entry[] }> {
    return this.http.put<{ list: Trump2025Entry[] }>(
      `${this.base}/api/admin/trump2025/list`,
      { list },
    );
  }

  /**
   * Look up the Trump 2025 rate for a single FOB country. The backend does
   * alias-aware case-insensitive matching ("PRC" → "China", etc.).
   */
  lookupTrump2025(country: string): Observable<Trump2025LookupResult> {
    return this.http.get<Trump2025LookupResult>(
      `${this.base}/api/admin/trump2025/lookup`,
      { params: { country } },
    );
  }

  // ── Factories (country admin + sub-grid auto-fill) ──────────────────────────

  /** Admin: full factory list with country column. */
  listFactories(): Observable<{ factories: FactoryRow[] }> {
    return this.http.get<{ factories: FactoryRow[] }>(
      `${this.base}/api/admin/factories`,
    );
  }

  /** Admin: update one factory's country. */
  updateFactoryCountry(id: number, factory_country: string | null): Observable<{ updated: number }> {
    return this.http.patch<{ updated: number }>(
      `${this.base}/api/admin/factories/${id}`,
      { factory_country },
    );
  }

  /**
   * Compact `{ factory_nickname: factory_country }` map used by the RFQ
   * sub-grid to pre-fill FOB Country when a vendor is picked.
   */
  getFactoryCountryMap(): Observable<{ map: Record<string, string> }> {
    return this.http.get<{ map: Record<string, string> }>(
      `${this.base}/api/admin/factories/countries`,
    );
  }
}

export interface Section301Result {
  hts: string;
  found: boolean;
  list?: string;
  rate?: number;
  description?: string;
  /** Whether the hit came from an admin override or the parsed PDF. */
  source?: 'override' | 'pdf';
}

/** Response shape from POST /api/admin/section301/upload-csv. */
export interface Section301CsvSummary {
  codesFound: number;
  lists: string[];
  /** Rows recognized as preamble/header/blank and skipped. */
  skipped: number;
  /** Rows where the same code appeared with a different list (first-wins). */
  conflicts: number;
  /** Rows that looked like data but failed validation (bad HTS shape or unknown list). */
  lineErrors: number;
}

/** One Section 301 override entry as stored in app_settings.section301_overrides. */
export interface Section301Override {
  list: string;
  rate: number;
  description?: string;
}
export type Section301OverrideMap = Record<string, Section301Override>;

/** One row of the admin-maintained Trump 2025 reciprocal-tariff table. */
export interface Trump2025Entry {
  country: string;
  rate: number;
}

/** Lookup response shape. `matchedAs` is the normalized form that hit. */
export interface Trump2025LookupResult {
  found: boolean;
  country: string | null;
  rate: number | null;
  matchedAs: string | null;
}

/** One row of the admin factory list. */
export interface FactoryRow {
  id: number;
  factory_name: string | null;
  factory_nickname: string | null;
  factory_country: string | null;
  factory_status: string | null;
}

export interface HtsRateResult {
  found: boolean;
  /** The code that actually matched (may differ from the queried code via prefix fallback). */
  hts: string | null;
  /** Parsed decimal percent. Null when the schedule's rate is non-ad-valorem (e.g. cents/kg)
   *  OR when the AI returned an invalid heading-only code and subheadings disagree on rate. */
  rate: number | null;
  /** Raw `general` column text from the USITC schedule, e.g. "5.3%" or "13.5¢/kg + 4.4%". */
  rateText: string | null;
  description: string | null;
  /** prefix4-ambiguous = code reached only at heading level and subheadings have different rates. */
  matchType: 'exact' | 'prefix8' | 'prefix6' | 'prefix4' | 'prefix4-ambiguous' | null;
}

