/**
 * GET /api/admin/trump2025/lookup?country=Vietnam
 * Look up the Trump 2025 rate for a given country.
 */
async function lookupTrump2025(req, res) {
  try {
    const { country } = req.query;
    if (!country) return res.status(400).json({ error: 'country query param is required' });
    const raw = await AppSettingService.get(TRUMP_2025_KEY);
    const list = raw ? JSON.parse(raw) : [];
    const result = trump2025.lookupRate(Array.isArray(list) ? list : [], country);
    if (!result.found) return res.status(404).json({ country, found: false });
    res.json(result);
  } catch (err) {
    console.error('[trump2025/lookup] error:', err.message);
    res.status(500).json({ error: err.message });
  }
}

