jest.mock('../../models/db', () => ({
  users: { findOne: jest.fn() },
  vendor: { findOne: jest.fn() },
  Factory: { findOne: jest.fn() },
}));

jest.mock('../../helpers/auth', () => ({
  getUserInfo: jest.fn(),
}));

jest.mock('jsonwebtoken', () => ({
  sign: jest.fn(() => 'signed-token'),
}));

const sql = require('../../models/db');
const { getUserInfo } = require('../../helpers/auth');
const jwt = require('jsonwebtoken');
const { startImpersonation } = require('../../controllers/admin.controller');

describe('admin startImpersonation', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    process.env.JWT_PRIVATE_KEY = 'test-private-key';
    getUserInfo.mockResolvedValue({ user_id: 15 });
  });

  test('impersonates a factory rep by vendor_id when targetType is vendor', async () => {
    sql.vendor.findOne.mockResolvedValue({
      vendor_id: 44,
      vendor_name: 'Factory',
      vendor_lastname: 'Rep',
      vendor_email: 'rep@example.com',
      vendor_access: 'permanent',
      factory_id_fk: 12,
    });

    const req = {
      params: { userId: '44' },
      body: { targetType: 'vendor' },
      headers: { authorization: 'Bearer admin-token' },
    };
    const res = mockResponse();

    await startImpersonation(req, res);

    expect(sql.users.findOne).not.toHaveBeenCalled();
    expect(sql.vendor.findOne).toHaveBeenCalledWith({
      where: { vendor_id: '44' },
      attributes: [
        'vendor_id',
        'vendor_name',
        'vendor_lastname',
        'vendor_email',
        'vendor_access',
        'vendor_company_nickname',
        'factory_id_fk',
      ],
    });
    expect(jwt.sign).toHaveBeenCalledWith({
      name: 'Factory Rep',
      user_id: 44,
      email: 'rep@example.com',
      role: 'vendor',
      access: 'permanent',
      factory_id: 12,
      impersonated_by: 15,
    }, 'test-private-key', {
      algorithm: 'RS256',
      expiresIn: '2h',
    });
    expect(res.json).toHaveBeenCalledWith({ token: 'signed-token' });
  });

  test('impersonates a visible factory row by factory id when targetType is factory', async () => {
    sql.Factory.findOne.mockResolvedValue({
      id: 31,
      factory_name: 'Ningbo Home Decor',
      factory_nickname: 'Jerome',
      factory_access: 'permanent',
    });
    sql.vendor.findOne.mockResolvedValue(null);

    const req = {
      params: { userId: '31' },
      body: { targetType: 'factory' },
      headers: { authorization: 'Bearer admin-token' },
