// Tariff lookups (HTS MFN rate + Trump 2025 reciprocal) must treat "no match"
// as a normal result (HTTP 200, found:false), NOT a 404. Returning 404 made the
// RFQ "Duty With $ and %" dialog trigger a spurious global error toast on open,
// because the frontend HttpErrorInterceptor toasts every HTTP error response.
jest.mock('../../models/db', () => ({}));

jest.mock('../../services/app-setting.service', () => ({
  get: jest.fn(),
  set: jest.fn(),
}));

jest.mock('../../helpers/hts-rates', () => ({
  lookupRate: jest.fn(),
}));

jest.mock('../../helpers/trump2025', () => ({
  lookupRate: jest.fn(),
  parseList: jest.fn(),
}));

const AppSettingService = require('../../services/app-setting.service');
const htsRates = require('../../helpers/hts-rates');
const trump2025 = require('../../helpers/trump2025');
const { lookupHtsRate, lookupTrump2025 } = require('../../controllers/admin.controller');

function mockResponse() {
  return {
    status: jest.fn().mockReturnThis(),
    json: jest.fn(),
  };
}

describe('admin lookupHtsRate', () => {
  beforeEach(() => jest.clearAllMocks());

  test('returns 200 found:false (not 404) when the code is not in the schedule', async () => {
    htsRates.lookupRate.mockReturnValue({ found: false });
    const res = mockResponse();

    await lookupHtsRate({ query: { hts: '0000.00.00' } }, res);

    expect(res.status).not.toHaveBeenCalled();
    expect(res.json).toHaveBeenCalledWith({
      hts: '0000.00.00', found: false, rate: null, rateText: null, description: null, matchType: null,
    });
  });

  test('returns the full result on a hit', async () => {
    const hit = { found: true, hts: '6304.93.00.00', rate: 11.3, rateText: '11.3%', description: 'Curtains', matchType: 'exact' };
    htsRates.lookupRate.mockReturnValue(hit);
    const res = mockResponse();

    await lookupHtsRate({ query: { hts: '6304.93.00.00' } }, res);

    expect(res.status).not.toHaveBeenCalled();
    expect(res.json).toHaveBeenCalledWith(hit);
  });

  test('still 400s when the hts query param is missing', async () => {
    const res = mockResponse();
    await lookupHtsRate({ query: {} }, res);
    expect(res.status).toHaveBeenCalledWith(400);
  });
});

describe('admin lookupTrump2025', () => {
  beforeEach(() => jest.clearAllMocks());

  test('returns 200 found:false (not 404) when the country is not on the list', async () => {
    AppSettingService.get.mockResolvedValue(JSON.stringify([{ country: 'China', rate: 25 }]));
    trump2025.lookupRate.mockReturnValue({ found: false });
    const res = mockResponse();

    await lookupTrump2025({ query: { country: 'Narnia' } }, res);

    expect(res.status).not.toHaveBeenCalled();
    expect(res.json).toHaveBeenCalledWith({ found: false, country: 'Narnia', rate: null, matchedAs: null });
  });

  test('returns the matched rate on a hit', async () => {
    const hit = { found: true, country: 'China', rate: 25, matchedAs: 'China' };
    AppSettingService.get.mockResolvedValue(JSON.stringify([{ country: 'China', rate: 25 }]));
    trump2025.lookupRate.mockReturnValue(hit);
    const res = mockResponse();

    await lookupTrump2025({ query: { country: 'PRC' } }, res);

    expect(res.status).not.toHaveBeenCalled();
    expect(res.json).toHaveBeenCalledWith(hit);
  });

  test('still 400s when the country query param is missing', async () => {
    const res = mockResponse();
    await lookupTrump2025({ query: {} }, res);
    expect(res.status).toHaveBeenCalledWith(400);
  });
});

